import {
  processPayment,
  PaymentError,
  PaymentInput,
  FraudService,
  PaymentGateway,
} from "./processPayment";

// ─── Test fixtures ────────────────────────────────────────────────────────────

const validInput: PaymentInput = {
  amount: 100,
  currency: "USD",
  userId: "user-42",
};

function makeFraudService(overrides?: Partial<FraudService>): FraudService {
  return {
    check: jest.fn().mockResolvedValue({ isFraudulent: false }),
    ...overrides,
  };
}

function makeGateway(overrides?: Partial<PaymentGateway>): PaymentGateway {
  return {
    charge: jest
      .fn()
      .mockResolvedValue({ success: true, transactionId: "txn-abc-123" }),
    ...overrides,
  };
}

// ─── AC1: Happy path ──────────────────────────────────────────────────────────

describe("AC1 – valid input returns { success: true, transaction_id }", () => {
  it("calls fraudService then gateway, and returns the transaction id", async () => {
    const fraudService = makeFraudService();
    const gateway = makeGateway();

    const result = await processPayment(validInput, fraudService, gateway);

    // Both services were called
    expect(fraudService.check).toHaveBeenCalledWith(validInput);
    expect(gateway.charge).toHaveBeenCalledWith(validInput);

    // Correct shape returned
    expect(result).toEqual({ success: true, transaction_id: "txn-abc-123" });
  });

  it("fraudService is called before gateway (ordering guarantee)", async () => {
    const callOrder: string[] = [];
    const fraudService: FraudService = {
      check: jest.fn().mockImplementation(async () => {
        callOrder.push("fraud");
        return { isFraudulent: false };
      }),
    };
    const gateway: PaymentGateway = {
      charge: jest.fn().mockImplementation(async () => {
        callOrder.push("gateway");
        return { success: true, transactionId: "txn-order-test" };
      }),
    };

    await processPayment(validInput, fraudService, gateway);

    expect(callOrder).toEqual(["fraud", "gateway"]);
  });
});

// ─── AC2 + AC6: Fraud detected ────────────────────────────────────────────────

describe("AC2 + AC6 – fraud flagged: throws FRAUD_DETECTED, gateway never called", () => {
  it("throws PaymentError with code FRAUD_DETECTED when fraud check returns isFraudulent=true", async () => {
    const fraudService = makeFraudService({
      check: jest.fn().mockResolvedValue({ isFraudulent: true }),
    });
    const gateway = makeGateway();

    await expect(
      processPayment(validInput, fraudService, gateway)
    ).rejects.toMatchObject({
      code: "FRAUD_DETECTED",
    });
  });

  it("does NOT call the payment gateway when fraud is detected (AC6 no side effects)", async () => {
    const fraudService = makeFraudService({
      check: jest.fn().mockResolvedValue({ isFraudulent: true }),
    });
    const gateway = makeGateway();

    await expect(
      processPayment(validInput, fraudService, gateway)
    ).rejects.toThrow(PaymentError);

    expect(gateway.charge).not.toHaveBeenCalled();
  });
});

// ─── AC3: Payment gateway decline ────────────────────────────────────────────

describe("AC3 – gateway decline: throws PAYMENT_DECLINED with decline reason", () => {
  it("throws PaymentError with code PAYMENT_DECLINED when gateway returns success=false", async () => {
    const fraudService = makeFraudService();
    const gateway = makeGateway({
      charge: jest
        .fn()
        .mockResolvedValue({ success: false, declineReason: "Insufficient funds" }),
    });

    await expect(
      processPayment(validInput, fraudService, gateway)
    ).rejects.toMatchObject({
      code: "PAYMENT_DECLINED",
      message: "Insufficient funds",
    });
  });

  it("uses a default message when the gateway omits declineReason", async () => {
    const fraudService = makeFraudService();
    const gateway = makeGateway({
      charge: jest.fn().mockResolvedValue({ success: false }),
    });

    const error = await processPayment(validInput, fraudService, gateway).catch(
      (e) => e
    );

    expect(error).toBeInstanceOf(PaymentError);
    expect(error.code).toBe("PAYMENT_DECLINED");
    expect(error.message).toBeTruthy();
  });
});

// ─── AC4: Fraud service unavailable ──────────────────────────────────────────

describe("AC4 – fraud service network error: throws FRAUD_SERVICE_UNAVAILABLE", () => {
  it("throws PaymentError with code FRAUD_SERVICE_UNAVAILABLE when fraudService throws", async () => {
    const networkError = new Error("ECONNREFUSED");
    const fraudService = makeFraudService({
      check: jest.fn().mockRejectedValue(networkError),
    });
    const gateway = makeGateway();

    await expect(
      processPayment(validInput, fraudService, gateway)
    ).rejects.toMatchObject({
      code: "FRAUD_SERVICE_UNAVAILABLE",
    });
  });

  it("chains the original error as cause (AC4 error chaining)", async () => {
    const networkError = new Error("ECONNREFUSED");
    const fraudService = makeFraudService({
      check: jest.fn().mockRejectedValue(networkError),
    });
    const gateway = makeGateway();

    const error: PaymentError = await processPayment(
      validInput,
      fraudService,
      gateway
    ).catch((e) => e);

    expect(error.cause).toBe(networkError);
  });

  it("does NOT call gateway when fraud service is unavailable", async () => {
    const fraudService = makeFraudService({
      check: jest.fn().mockRejectedValue(new Error("timeout")),
    });
    const gateway = makeGateway();

    await expect(
      processPayment(validInput, fraudService, gateway)
    ).rejects.toThrow(PaymentError);

    expect(gateway.charge).not.toHaveBeenCalled();
  });
});

// ─── AC5: Gateway unavailable ────────────────────────────────────────────────

describe("AC5 – gateway network error: throws GATEWAY_UNAVAILABLE", () => {
  it("throws PaymentError with code GATEWAY_UNAVAILABLE when gateway throws", async () => {
    const fraudService = makeFraudService();
    const networkError = new Error("ETIMEDOUT");
    const gateway = makeGateway({
      charge: jest.fn().mockRejectedValue(networkError),
    });

    await expect(
      processPayment(validInput, fraudService, gateway)
    ).rejects.toMatchObject({
      code: "GATEWAY_UNAVAILABLE",
    });
  });

  it("chains the original error as cause (AC5 error chaining)", async () => {
    const fraudService = makeFraudService();
    const networkError = new Error("ETIMEDOUT");
    const gateway = makeGateway({
      charge: jest.fn().mockRejectedValue(networkError),
    });

    const error: PaymentError = await processPayment(
      validInput,
      fraudService,
      gateway
    ).catch((e) => e);

    expect(error.cause).toBe(networkError);
  });
});

// ─── PaymentError shape ───────────────────────────────────────────────────────

describe("PaymentError class", () => {
  it("has name='PaymentError', code, and optional cause", () => {
    const cause = new Error("root");
    const err = new PaymentError("FRAUD_DETECTED", "msg", cause);

    expect(err.name).toBe("PaymentError");
    expect(err.code).toBe("FRAUD_DETECTED");
    expect(err.message).toBe("msg");
    expect(err.cause).toBe(cause);
    expect(err).toBeInstanceOf(Error);
  });
});

